"use client";

import { motion } from "framer-motion";

export default function ElasticModuleMeter() {
  return (() => <div role="status" aria-label="Loading six elastic modules" style={{display:"grid",placeItems:"center",height:"100%",minHeight:230,background:"#f4f5f6",borderRadius:20}}><div style={{display:"flex",gap:7,alignItems:"end"}}>{Array.from({length:6},(_,i)=><motion.span key={i} animate={{height:[50,92,50],backgroundColor:["#111",i%2?"#f5e642":"#53e8d4","#111"]}} transition={{duration:1.65,repeat:Infinity,delay:i*.075,type:"spring",stiffness:430,damping:20}} style={{width:40,height:50,borderRadius:12,background:i===5?"#ff9950":"#111"}}/>)}</div></div>)();
