/* Suggested markup: <div class="uiwiki-elastic-module-meter" tabindex="0"><span>Elastic Module Meter</span></div> */
.uiwiki-elastic-module-meter {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-elastic-module-meter > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #ff9950;
  animation: elastic_module_meter 1.8s ease-in-out infinite alternate;
}
.uiwiki-elastic-module-meter:hover,
.uiwiki-elastic-module-meter:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes elastic_module_meter {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-elastic-module-meter, .uiwiki-elastic-module-meter > span { animation: none; transition: none; }
}
